# C Project Makefile
# Standard build targets and configuration

CC = gcc
CFLAGS = -Wall -Wextra -std=c99 -pedantic
CFLAGS_DEBUG = -g -O0
CFLAGS_RELEASE = -O2 -DNDEBUG
LDFLAGS = 

# Project structure
SRC_DIR = src
BUILD_DIR = build
BIN_DIR = $(BUILD_DIR)/bin
OBJ_DIR = $(BUILD_DIR)/obj

# Source files
SOURCES = $(SRC_DIR)/main.c
OBJECTS = $(OBJ_DIR)/main.o
TARGET = $(BIN_DIR)/app

# Default target
.PHONY: all
all: $(TARGET)

# Build directory structure
$(BIN_DIR) $(OBJ_DIR):
	@mkdir -p $@

# Object files
$(OBJ_DIR)/%.o: $(SRC_DIR)/%.c | $(OBJ_DIR)
	$(CC) $(CFLAGS) -c $< -o $@

# Main executable
$(TARGET): $(OBJECTS) | $(BIN_DIR)
	$(CC) $(CFLAGS) $(LDFLAGS) -o $@ $^

# Debug build
.PHONY: debug
debug: CFLAGS += $(CFLAGS_DEBUG)
debug: clean $(TARGET)
	@echo "Debug build complete: $(TARGET)"

# Release build
.PHONY: release
release: CFLAGS += $(CFLAGS_RELEASE)
release: clean $(TARGET)
	@echo "Release build complete: $(TARGET)"
	strip $(TARGET)

# Run the application
.PHONY: run
run: $(TARGET)
	@./$(TARGET)

# Install (copy binary to system location)
.PHONY: install
install: release
	@echo "Installing $(TARGET) to /usr/local/bin/app"
	@mkdir -p /usr/local/bin
	@cp $(TARGET) /usr/local/bin/app
	@chmod +x /usr/local/bin/app
	@echo "Installation complete"

# Clean build artifacts
.PHONY: clean
clean:
	@rm -rf $(BUILD_DIR)
	@echo "Build artifacts cleaned"

# Deep clean (remove all generated files)
.PHONY: distclean
distclean: clean
	@echo "Distribution clean complete"

# Display help
.PHONY: help
help:
	@echo "C Project Build System"
	@echo "====================="
	@echo "Usage: make [target]"
	@echo ""
	@echo "Targets:"
	@echo "  all       - Build the project (default)"
	@echo "  debug     - Build with debugging symbols"
	@echo "  release   - Build optimized release binary"
	@echo "  run       - Build and run the application"
	@echo "  install   - Build release and install to /usr/local/bin"
	@echo "  clean     - Remove build artifacts"
	@echo "  distclean - Remove all generated files"
	@echo "  help      - Display this help message"
	@echo ""
	@echo "Examples:"
	@echo "  make              # Build the project"
	@echo "  make debug        # Build with debugging symbols"
	@echo "  make release      # Build optimized version"
	@echo "  make run          # Build and execute"
	@echo "  make clean        # Clean up"
